module sr_latch (  
    input inv_S,  
    input R,  
    output reg Q,  
    output reg Q_not  
);  
    always @ (inv_S or R) begin  
        if (inv_S && !R) begin  
            Q = 1;  
            Q_not = 0;  
        end else if (!inv_S && R) begin  
            Q = 0;  
            Q_not = 1;  
        end  
        // Hold state if both inv_S and R are low  
    end  
endmodule
